import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.iterator.reduce.js";
import LogPanel from '@/components/LogPanel.vue';
import { validateImage, fileToDataURL, getImageDimensions, formatFileSize } from '@/utils/imageUtils';
import { analyzeImage, checkHealth } from '@/api/pigModel';
import { getDetectionStats } from '@/api/detectionApi';
export default {
  name: 'HomePage',
  components: {
    LogPanel
  },
  data() {
    return {
      isDragging: false,
      hoveredBox: null,
      animatedCount: 0,
      showImagePreview: false,
      // 系统统计数据
      systemStats: {
        total_images: 0,
        total_pigs: 0,
        today_images: 0,
        today_pigs: 0
      },
      // 服务状态
      serviceHealthy: true,
      serviceChecking: false,
      // 统计卡片数据
      statCards: [{
        icon: '🐷',
        value: null,
        label: '当前识别',
        unit: '头',
        cls: 'stat-num stat-sm',
        active: false
      }, {
        icon: '📸',
        value: 0,
        label: '上传图片',
        unit: '张',
        cls: '',
        active: false
      }, {
        icon: '⚡',
        value: 0,
        label: '平均耗时',
        unit: 'ms',
        cls: '',
        active: false
      }, {
        icon: '🎯',
        value: 0,
        label: '平均置信度',
        unit: '%',
        cls: '',
        active: false
      }],
      // 图片相关
      previewUrl: '',
      imageMeta: null,
      annotatedImage: '',
      inferenceTime: null,
      // 识别结果
      result: {
        boxes: []
      },
      // 动画相关
      uploadProgress: 0,
      toastProgress: 0,
      isAnalyzing: false
    };
  },
  computed: {
    // 从 store 获取数据
    hasImage() {
      return this.$store.state.imageFiles.length > 0;
    },
    hasResult() {
      return this.$store.state.results.length > 0;
    },
    year() {
      return new Date().getFullYear();
    },
    // 计算属性：当前猪场 ID
    selectedFarmId() {
      return this.$store.state.selectedFarmId;
    },
    // 计算属性：当前猪场名称
    currentFarmName() {
      if (!this.selectedFarmId) return '未选择';
      const farm = this.$store.state.farms.find(f => f.id === this.selectedFarmId);
      return farm ? farm.name : '未选择';
    },
    // 计算属性：当前结果
    result() {
      return this.$store.state.currentResult || {
        boxes: []
      };
    },
    // 计算属性：猪只数量
    pigCount() {
      return this.result.boxes.length;
    },
    // 计算属性：平均置信度
    confidencePct() {
      if (!this.result.boxes.length) return 0;
      const sum = this.result.boxes.reduce((acc, box) => acc + box.score, 0);
      return Math.round(sum / this.result.boxes.length * 100);
    },
    // 计算属性：置信度样式类
    confClass() {
      const conf = this.confidencePct;
      if (conf >= 80) return 'conf-high';
      if (conf >= 60) return 'conf-mid';
      return 'conf-low';
    },
    // 计算属性：服务状态样式
    serviceClass() {
      return this.serviceHealthy ? 'service-pill--ok' : 'service-pill--error';
    },
    // 计算属性：服务状态标签
    serviceLabel() {
      if (this.serviceChecking) return '检查中...';
      return this.serviceHealthy ? '服务正常' : '服务离线';
    }
  },
  mounted() {
    this.loadSystemStats();
    this.checkServiceHealth();
  },
  methods: {
    // 加载系统统计数据
    async loadSystemStats() {
      try {
        const stats = await getDetectionStats();
        this.systemStats = stats;
        this.statCards[1].value = this.$store.state.imageFiles.length;
      } catch (err) {
        console.error('加载统计数据失败:', err);
      }
    },
    // 检查服务健康状态
    async checkServiceHealth() {
      this.serviceChecking = true;
      try {
        const status = await checkHealth();
        this.serviceHealthy = status.healthy;
        this.$store.commit('setServiceOnline', status.healthy);
      } catch (err) {
        this.serviceHealthy = false;
        this.$store.commit('setServiceOnline', false);
      } finally {
        this.serviceChecking = false;
      }
    },
    // 上传文件处理
    onDrop(e) {
      this.isDragging = false;
      const files = Array.from(e.dataTransfer.files);
      this.processFiles(files);
    },
    // 处理文件输入
    onDropInputChange(e) {
      const files = Array.from(e.target.files);
      this.processFiles(files);
    },
    // 处理文件
    async processFiles(files) {
      const imageFiles = [];
      for (const file of files) {
        if (validateImage(file)) {
          const dataURL = await fileToDataURL(file);
          const {
            width,
            height
          } = await getImageDimensions(dataURL);
          imageFiles.push({
            file,
            dataURL,
            name: file.name,
            size: formatFileSize(file.size),
            width,
            height
          });
        }
      }
      if (imageFiles.length > 0) {
        this.$store.commit('setImageFiles', imageFiles);
        this.$store.commit('setCurrentImageIndex', 0);
        this.updateImageMeta();
        this.statCards[1].value = imageFiles.length;
      }
    },
    // 更新图片元数据
    updateImageMeta() {
      if (this.$store.state.imageFiles.length > 0) {
        const currentFile = this.$store.state.imageFiles[this.$store.state.currentImageIndex];
        this.imageMeta = {
          name: currentFile.name,
          size: currentFile.size,
          width: currentFile.width,
          height: currentFile.height
        };
        this.previewUrl = currentFile.dataURL;
      } else {
        this.imageMeta = null;
        this.previewUrl = '';
      }
    },
    // 上一张图片
    prevImage() {
      if (this.$store.state.imageFiles.length > 1) {
        const currentIndex = this.$store.state.currentImageIndex;
        const newIndex = (currentIndex - 1 + this.$store.state.imageFiles.length) % this.$store.state.imageFiles.length;
        this.$store.commit('setCurrentImageIndex', newIndex);
        this.updateImageMeta();
        if (this.$store.state.results.length > 0) {
          this.drawBoxes();
        }
      }
    },
    // 下一张图片
    nextImage() {
      if (this.$store.state.imageFiles.length > 1) {
        const currentIndex = this.$store.state.currentImageIndex;
        const newIndex = (currentIndex + 1) % this.$store.state.imageFiles.length;
        this.$store.commit('setCurrentImageIndex', newIndex);
        this.updateImageMeta();
        if (this.$store.state.results.length > 0) {
          this.drawBoxes();
        }
      }
    },
    // 运行分析
    async runAnalysis() {
      if (!this.hasImage || !this.selectedFarmId || this.isAnalyzing || !this.$store.state.serviceOnline) return;
      this.isAnalyzing = true;
      this.uploadProgress = 0;
      try {
        const results = [];
        const totalFiles = this.$store.state.imageFiles.length;
        for (let i = 0; i < totalFiles; i++) {
          this.$store.commit('setCurrentImageIndex', i);
          const file = this.$store.state.imageFiles[i].file;

          // 模拟上传进度
          this.uploadProgress = Math.round(i / totalFiles * 100);

          // 分析图片
          const startTime = Date.now();
          const result = await analyzeImage(file, this.selectedFarmId);
          const endTime = Date.now();
          results.push({
            ...result,
            inference_time: endTime - startTime
          });
        }
        this.$store.commit('setResults', results);
        this.$store.commit('setCurrentImageIndex', 0);

        // 计算统计数据
        const totalPigs = results.reduce((sum, r) => sum + r.boxes.length, 0);
        const totalTime = results.reduce((sum, r) => sum + r.inference_time, 0);
        const avgTime = Math.round(totalTime / results.length);
        const avgConfidence = Math.round(results.reduce((sum, r) => {
          const confSum = r.boxes.reduce((cSum, box) => cSum + box.score, 0);
          return sum + confSum / r.boxes.length;
        }, 0) / results.length * 100);

        // 更新统计卡片
        this.statCards[0].value = totalPigs;
        this.statCards[2].value = avgTime;
        this.statCards[3].value = avgConfidence;

        // 生成带标注的图片
        this.generateAnnotatedImage();

        // 显示成功提示
        if (results.length > 1) {
          this.showToastMessage(`识别完成：${results.length} 张图片，共检测到 ${totalPigs} 头猪`, 'toast-success', 3000);
        } else {
          this.showToastMessage(`识别完成：检测到 ${totalPigs} 头猪`, 'toast-success', 3000);
        }

        // 重新加载系统统计数据
        this.loadSystemStats();
      } catch (err) {
        console.error('分析失败:', err);
        this.showToastMessage('识别失败：' + err.message, 'toast-error', 4000);
      } finally {
        this.isAnalyzing = false;
        this.uploadProgress = 100;

        // 延迟关闭提示栏，让用户看到完成状态
        setTimeout(() => {
          this.uploadProgress = 0;
        }, 1000);
      }
    },
    // 生成带标注的图片
    generateAnnotatedImage() {
      if (!this.hasResult) return;
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.onload = () => {
        canvas.width = img.width;
        canvas.height = img.height;
        ctx.drawImage(img, 0, 0);

        // 绘制 bounding boxes
        this.result.boxes.forEach(box => {
          const [x, y, width, height] = box.xywh;
          ctx.strokeStyle = '#00ff00';
          ctx.lineWidth = 2;
          ctx.strokeRect(x, y, width, height);

          // 绘制标签
          ctx.fillStyle = 'rgba(0, 255, 0, 0.7)';
          ctx.font = '12px Arial';
          ctx.fillText(`${box.class_name} ${(box.score * 100).toFixed(1)}%`, x, y - 5);
        });
        this.annotatedImage = canvas.toDataURL('image/png');
      };
      img.src = this.previewUrl;
    },
    // 绘制边界框
    drawBoxes() {
      if (!this.hasResult) return;
      const baseImg = this.$refs.baseImg;
      const boxCanvas = this.$refs.boxCanvas;
      if (!baseImg || !boxCanvas) return;
      const ctx = boxCanvas.getContext('2d');
      boxCanvas.width = baseImg.width;
      boxCanvas.height = baseImg.height;
      ctx.clearRect(0, 0, boxCanvas.width, boxCanvas.height);
      this.result.boxes.forEach(box => {
        const [x, y, width, height] = box.xywh;
        ctx.strokeStyle = '#00ff00';
        ctx.lineWidth = 2;
        ctx.strokeRect(x, y, width, height);

        // 绘制标签
        ctx.fillStyle = 'rgba(0, 255, 0, 0.7)';
        ctx.font = '12px Arial';
        ctx.fillText(`${box.class_name} ${(box.score * 100).toFixed(1)}%`, x, y - 5);
      });
    },
    // 打开图片预览
    openImagePreview() {
      if (this.hasResult && this.annotatedImage) {
        this.showImagePreview = true;
        document.body.style.overflow = 'hidden';
      }
    },
    // 关闭图片预览
    closeImagePreview() {
      this.showImagePreview = false;
      document.body.style.overflow = '';
    },
    // 清除图片
    clearImage() {
      this.$store.commit('setImageFiles', []);
      this.$store.commit('setResults', []);
      this.imageMeta = null;
      this.previewUrl = '';
      this.annotatedImage = '';
      this.inferenceTime = null;
      this.statCards[0].value = null;
      this.statCards[1].value = 0;
      this.statCards[2].value = 0;
      this.statCards[3].value = 0;
    },
    // 格式化坐标
    formatCoord(box) {
      const [x, y, width, height] = box.xywh;
      return `${Math.round(x)}, ${Math.round(y)}, ${Math.round(width)}, ${Math.round(height)}`;
    },
    // 获取置信度样式类
    getConfClass(score) {
      if (score >= 0.8) return 'conf-high';
      if (score >= 0.6) return 'conf-mid';
      return 'conf-low';
    },
    // 行悬停
    onRowHover(index) {
      this.hoveredBox = index;
    },
    // 结果图片加载完成
    onResultImgLoad() {
      if (this.hasResult) {
        this.drawBoxes();
      }
    },
    // 显示提示信息
    showToastMessage(message, type = 'toast-info', duration = 3000) {
      this.$emit('show-toast', {
        message,
        type,
        duration
      });
    },
    // 显示带进度的提示信息
    showToastWithProgress(message, type = 'toast-info') {
      this.$emit('show-toast-with-progress', {
        message,
        type
      });
    },
    // 关闭提示信息
    closeToast() {
      this.$emit('close-toast');
    },
    // 获取分析按钮标题
    getAnalyzeBtnTitle() {
      if (!this.hasImage) return '请先上传图片';
      if (!this.selectedFarmId) return '请先选择猪场';
      if (this.isAnalyzing) return '识别中...';
      if (!this.$store.state.serviceOnline) return '服务离线，无法识别';
      return '开始识别';
    }
  },
  watch: {
    // 监听当前图片索引变化
    '$store.state.currentImageIndex': function () {
      this.updateImageMeta();
      if (this.hasResult) {
        this.drawBoxes();
      }
    },
    // 监听结果变化
    '$store.state.results': function () {
      if (this.hasResult) {
        this.generateAnnotatedImage();
        this.drawBoxes();
      }
    }
  }
};
